import * as React from "react";

import { cn } from "@/lib/utils";

import "./magnetic-shadow-animation.css";

type MagneticShadowTimingValue = number | string;
type CssVariableStyle = React.CSSProperties & Record<`--${string}`, string>;

export type MagneticShadowProps = React.ComponentPropsWithoutRef<"span"> & {
  /** Keep the gathered state active without requiring hover. */
  active?: boolean;
  /** Animation duration for release. Numeric values are converted to ms. */
  duration?: MagneticShadowTimingValue;
  /** Animation duration for gather. Numeric values are converted to ms. */
  activeDuration?: MagneticShadowTimingValue;
  /** CSS easing used by the transform and opacity transitions. */
  ease?: string;
  /** Optional decorative content for the shadow layers. Defaults to children. */
  shadow?: React.ReactNode;
  /** Classes applied to the visible animated child wrapper. */
  targetClassName?: string;
  /** Classes applied to the far projected shadow layer. */
  projectedShadowClassName?: string;
  /** Classes applied to the close contact shadow layer. */
  contactShadowClassName?: string;
  /** Hide the far projected shadow layer. */
  showProjectedShadow?: boolean;
  /** Hide the close contact shadow layer. */
  showContactShadow?: boolean;
};

export function MagneticShadow({
  active,
  activeDuration,
  children,
  className,
  contactShadowClassName,
  duration,
  ease,
  projectedShadowClassName,
  shadow,
  showContactShadow = true,
  showProjectedShadow = true,
  style,
  targetClassName,
  ...props
}: MagneticShadowProps) {
  const shadowContent = shadow ?? children;

  return (
    <span
      data-slot="magnetic-shadow"
      data-active={active ? "true" : undefined}
      className={cn(
        "magnetic-shadow relative inline-flex items-center justify-center",
        className,
      )}
      style={getMagneticShadowStyle({ activeDuration, duration, ease }, style)}
      {...props}
    >
      {showProjectedShadow ? (
        <span
          aria-hidden="true"
          data-slot="magnetic-shadow-projected"
          className={cn(
            "magnetic-shadow-layer magnetic-shadow-projected pointer-events-none absolute inset-0 z-0 inline-flex text-current blur-[6px]",
            projectedShadowClassName,
          )}
        >
          {shadowContent}
        </span>
      ) : null}

      {showContactShadow ? (
        <span
          aria-hidden="true"
          data-slot="magnetic-shadow-contact"
          className={cn(
            "magnetic-shadow-layer magnetic-shadow-contact pointer-events-none absolute inset-0 z-0 inline-flex text-current",
            contactShadowClassName,
          )}
        >
          {shadowContent}
        </span>
      ) : null}

      <span
        data-slot="magnetic-shadow-target"
        className={cn(
          "magnetic-shadow-layer magnetic-shadow-target relative z-10 inline-flex text-current",
          targetClassName,
        )}
      >
        {children}
      </span>
    </span>
  );
}

function getMagneticShadowStyle(
  {
    activeDuration,
    duration,
    ease,
  }: Pick<MagneticShadowProps, "activeDuration" | "duration" | "ease">,
  style: React.CSSProperties | undefined,
) {
  if (activeDuration === undefined && duration === undefined && ease === undefined) {
    return style;
  }

  return {
    ...style,
    ...(activeDuration !== undefined
      ? { "--magnetic-shadow-active-duration": toCssTime(activeDuration) }
      : {}),
    ...(duration !== undefined
      ? { "--magnetic-shadow-duration": toCssTime(duration) }
      : {}),
    ...(ease !== undefined ? { "--magnetic-shadow-ease": ease } : {}),
  } as CssVariableStyle;
}

function toCssTime(value: MagneticShadowTimingValue) {
  return typeof value === "number" ? `${value}ms` : value;
}

.magnetic-shadow {
  --magnetic-shadow-duration: 280ms;
  --magnetic-shadow-active-duration: 360ms;
  --magnetic-shadow-ease: cubic-bezier(0.165, 0.84, 0.44, 1);
  --magnetic-shadow-origin: center;
  --magnetic-shadow-projected-opacity: 1;
  --magnetic-shadow-projected-active-opacity: 0;
  --magnetic-shadow-projected-x: -14%;
  --magnetic-shadow-projected-y: -18%;
  --magnetic-shadow-projected-scale: 1.08;
  --magnetic-shadow-projected-rotate: -8deg;
  --magnetic-shadow-projected-active-x: -4%;
  --magnetic-shadow-projected-active-y: -5%;
  --magnetic-shadow-projected-active-scale: 0.94;
  --magnetic-shadow-projected-active-rotate: -3deg;
  --magnetic-shadow-contact-opacity: 0;
  --magnetic-shadow-contact-active-opacity: 0.72;
  --magnetic-shadow-contact-x: -4%;
  --magnetic-shadow-contact-y: -5%;
  --magnetic-shadow-contact-scale: 0.92;
  --magnetic-shadow-contact-rotate: -2deg;
  --magnetic-shadow-contact-active-x: 0%;
  --magnetic-shadow-contact-active-y: 0%;
  --magnetic-shadow-contact-active-scale: 0.89;
  --magnetic-shadow-contact-active-rotate: 0deg;
  --magnetic-shadow-target-x: 8%;
  --magnetic-shadow-target-y: -6%;
  --magnetic-shadow-target-scale: 1.06;
  --magnetic-shadow-target-rotate: 10deg;
  --magnetic-shadow-target-active-x: 0%;
  --magnetic-shadow-target-active-y: 0%;
  --magnetic-shadow-target-active-scale: 0.86;
  --magnetic-shadow-target-active-rotate: 0deg;
}

.magnetic-shadow-layer {
  backface-visibility: hidden;
  transform-origin: var(--magnetic-shadow-origin);
  transition-property: opacity, transform;
  transition-duration: var(--magnetic-shadow-duration);
  transition-timing-function: var(--magnetic-shadow-ease);
  will-change: transform, opacity;
}

.magnetic-shadow-projected {
  opacity: var(--magnetic-shadow-projected-opacity);
  transform: translate3d(
      var(--magnetic-shadow-projected-x),
      var(--magnetic-shadow-projected-y),
      0
    )
    scale(var(--magnetic-shadow-projected-scale))
    rotate(var(--magnetic-shadow-projected-rotate));
}

.magnetic-shadow-contact {
  opacity: var(--magnetic-shadow-contact-opacity);
  transform: translate3d(
      var(--magnetic-shadow-contact-x),
      var(--magnetic-shadow-contact-y),
      0
    )
    scale(var(--magnetic-shadow-contact-scale))
    rotate(var(--magnetic-shadow-contact-rotate));
}

.magnetic-shadow-target {
  transform: translate3d(
      var(--magnetic-shadow-target-x),
      var(--magnetic-shadow-target-y),
      0
    )
    scale(var(--magnetic-shadow-target-scale))
    rotate(var(--magnetic-shadow-target-rotate));
}

.magnetic-shadow[data-active="true"] .magnetic-shadow-layer {
  transition-duration: var(--magnetic-shadow-active-duration);
}

.magnetic-shadow[data-active="true"] .magnetic-shadow-projected {
  opacity: var(--magnetic-shadow-projected-active-opacity);
  transform: translate3d(
      var(--magnetic-shadow-projected-active-x),
      var(--magnetic-shadow-projected-active-y),
      0
    )
    scale(var(--magnetic-shadow-projected-active-scale))
    rotate(var(--magnetic-shadow-projected-active-rotate));
}

.magnetic-shadow[data-active="true"] .magnetic-shadow-contact {
  opacity: var(--magnetic-shadow-contact-active-opacity);
  transform: translate3d(
      var(--magnetic-shadow-contact-active-x),
      var(--magnetic-shadow-contact-active-y),
      0
    )
    scale(var(--magnetic-shadow-contact-active-scale))
    rotate(var(--magnetic-shadow-contact-active-rotate));
}

.magnetic-shadow[data-active="true"] .magnetic-shadow-target {
  transform: translate3d(
      var(--magnetic-shadow-target-active-x),
      var(--magnetic-shadow-target-active-y),
      0
    )
    scale(var(--magnetic-shadow-target-active-scale))
    rotate(var(--magnetic-shadow-target-active-rotate));
}

@media (hover: hover) and (pointer: fine) {
  .magnetic-shadow:hover .magnetic-shadow-layer {
    transition-duration: var(--magnetic-shadow-active-duration);
  }

  .magnetic-shadow:hover .magnetic-shadow-projected {
    opacity: var(--magnetic-shadow-projected-active-opacity);
    transform: translate3d(
        var(--magnetic-shadow-projected-active-x),
        var(--magnetic-shadow-projected-active-y),
        0
      )
      scale(var(--magnetic-shadow-projected-active-scale))
      rotate(var(--magnetic-shadow-projected-active-rotate));
  }

  .magnetic-shadow:hover .magnetic-shadow-contact {
    opacity: var(--magnetic-shadow-contact-active-opacity);
    transform: translate3d(
        var(--magnetic-shadow-contact-active-x),
        var(--magnetic-shadow-contact-active-y),
        0
      )
      scale(var(--magnetic-shadow-contact-active-scale))
      rotate(var(--magnetic-shadow-contact-active-rotate));
  }

  .magnetic-shadow:hover .magnetic-shadow-target {
    transform: translate3d(
        var(--magnetic-shadow-target-active-x),
        var(--magnetic-shadow-target-active-y),
        0
      )
      scale(var(--magnetic-shadow-target-active-scale))
      rotate(var(--magnetic-shadow-target-active-rotate));
  }
}

@media (prefers-reduced-motion: reduce) {
  .magnetic-shadow-layer {
    transition-duration: 0ms;
    will-change: auto;
  }
}
